
import { Moon, Sun, LayoutDashboard, List, Bell, Settings as SettingsIcon } from 'lucide-react';
import Header from '@/components/landing/Header';
import Footer from '@/components/landing/Footer';
import { usePreferences } from '@/lib/usePreferences';
import { Reveal } from '@/components/landing/motion';

// Theme options
const THEME_OPTIONS = [
  { value: 'dark', label: 'Dark', icon: Moon },
  { value: 'light', label: 'Light', icon: Sun },
];

// Price format options
const PRICE_FORMAT_OPTIONS = [
  { value: 'compact', label: 'Compact (1.2k)' },
  { value: 'full', label: 'Full (1,200.00)' },
];

// Dashboard layout options
const DASHBOARD_LAYOUT_OPTIONS = [
  { value: 'default', label: 'Default', icon: LayoutDashboard },
  { value: 'compact', label: 'Compact', icon: LayoutDashboard },
];

// Listing density options
const LISTING_DENSITY_OPTIONS = [
  { value: 'comfortable', label: 'Comfortable', icon: List },
  { value: 'compact', label: 'Compact', icon: List },
];

// Notification type options
const NOTIFICATION_TYPES = [
  { type: 'priceAlerts', label: 'Price Alerts', icon: Bell },
  { type: 'systemUpdates', label: 'System Updates', icon: SettingsIcon },
];

// Setting section component
const SettingSection = ({ title, children }) => (
  <div className="mb-10">
    <h2 className="font-heading text-xl font-bold mb-4 text-white">{title}</h2>
    <div className="space-y-4">
      {children}
    </div>
  </div>
);

// Setting item component
const SettingItem = ({ label, children }) => (
  <div className="flex items-center justify-between p-4 bg-white/[0.02] rounded-lg">
    <div className="font-mono text-sm text-zinc-300">{label}</div>
    <div>{children}</div>
  </div>
);

// Radio option component
const RadioOption = ({ value, label, currentValue, onChange, icon: Icon }) => (
  <label className="flex items-center gap-2 p-2 rounded cursor-pointer hover:bg-white/[0.04] transition-colors">
    <input
      type="radio"
      value={value}
      checked={value === currentValue}
      onChange={() => onChange(value)}
      className="sr-only"
    />
    <div className={`w-4 h-4 rounded-full border-2 ${value === currentValue ? 'border-emerald-400 bg-emerald-400' : 'border-zinc-500'}`}>
      {value === currentValue && (
        <div className="w-1.5 h-1.5 rounded-full bg-white ml-[3px] mt-[3px]"></div>
      )}
    </div>
    {Icon && <Icon className="w-4 h-4 text-zinc-400" />}
    <span className="text-sm font-mono">{label}</span>
  </label>
);

// Toggle switch component
const ToggleSwitch = ({ checked, onChange, label }) => (
  <label className="flex items-center gap-2 cursor-pointer">
    <input
      type="checkbox"
      checked={checked}
      onChange={(e) => onChange(e.target.checked)}
      className="sr-only"
    />
    <div className={`w-10 h-5 rounded-full flex items-center ${checked ? 'bg-emerald-500' : 'bg-zinc-600'}`}>
      <div className={`w-4 h-4 rounded-full bg-white shadow transform transition-transform ${checked ? 'translate-x-5' : 'translate-x-0.5'}`}></div>
    </div>
    <span className="text-sm font-mono">{label}</span>
  </label>
);

export default function SettingsPage() {
  const { preferences, updatePreferences } = usePreferences();

  // Handle theme change
  const handleThemeChange = (theme) => {
    updatePreferences({ theme });
    document.documentElement.classList.toggle('dark', theme === 'dark');
  };



  return (
    <div className="min-h-screen bg-bg-base text-white font-body">
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-4xl mx-auto px-6 md:px-12 lg:px-16">
          <Reveal>
            <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-emerald-400 mb-4 inline-flex items-center gap-2">
              <SettingsIcon className="w-3 h-3" /> / Settings
            </div>
            <h1 className="font-heading text-5xl lg:text-6xl tracking-tighter font-black leading-[0.95] mb-8">
              Your <span className="text-emerald-400">Settings</span>
            </h1>
            <p className="text-zinc-400 max-w-2xl text-lg mb-12">
              Customize your Castia Market Insight experience.
            </p>
          </Reveal>

          <div className="space-y-8">
            {/* Theme settings */}
            <SettingSection title="Appearance">
              <SettingItem label="Theme">
                <div className="flex gap-1 bg-white/[0.04] p-1 rounded">
                  {THEME_OPTIONS.map((option) => (
                    <RadioOption
                      key={option.value}
                      value={option.value}
                      label={option.label}
                      currentValue={preferences.theme}
                      onChange={handleThemeChange}
                      icon={option.icon}
                    />
                  ))}
                </div>
              </SettingItem>

              <SettingItem label="Price Format">
                <div className="flex gap-1 bg-white/[0.04] p-1 rounded">
                  {PRICE_FORMAT_OPTIONS.map((option) => (
                    <RadioOption
                      key={option.value}
                      value={option.value}
                      label={option.label}
                      currentValue={preferences.priceFormat}
                      onChange={(value) => updatePreferences({ priceFormat: value })}
                    />
                  ))}
                </div>
              </SettingItem>

              <SettingItem label="Dashboard Layout">
                <div className="flex gap-1 bg-white/[0.04] p-1 rounded">
                  {DASHBOARD_LAYOUT_OPTIONS.map((option) => (
                    <RadioOption
                      key={option.value}
                      value={option.value}
                      label={option.label}
                      currentValue={preferences.dashboardLayout}
                      onChange={(value) => updatePreferences({ dashboardLayout: value })}
                      icon={option.icon}
                    />
                  ))}
                </div>
              </SettingItem>

              <SettingItem label="Listing Density">
                <div className="flex gap-1 bg-white/[0.04] p-1 rounded">
                  {LISTING_DENSITY_OPTIONS.map((option) => (
                    <RadioOption
                      key={option.value}
                      value={option.value}
                      label={option.label}
                      currentValue={preferences.listingDensity}
                      onChange={(value) => updatePreferences({ listingDensity: value })}
                      icon={option.icon}
                    />
                  ))}
                </div>
              </SettingItem>
            </SettingSection>

            {/* Notification settings */}
            <SettingSection title="Notifications">
              {NOTIFICATION_TYPES.map((notif) => (
                <SettingItem key={notif.type} label={notif.label}>
                  <ToggleSwitch
                    checked={preferences.notifications[notif.type]}
                    onChange={(enabled) => {
                      updatePreferences({
                        notifications: {
                          ...preferences.notifications,
                          [notif.type]: enabled,
                        },
                      });
                    }}
                  />
                </SettingItem>
              ))}
            </SettingSection>

            {/* Data privacy */}
            <SettingSection title="Data Privacy">
              <SettingItem label="Data Protection">
                <div className="text-xs font-mono text-zinc-400">
                  <p className="mb-2">Your data is stored locally in your browser and never sent to any server.</p>
                  <p>For additional privacy, you can clear your browser data at any time.</p>
                </div>
              </SettingItem>
            </SettingSection>
          </div>
        </div>
      </main>
      <Footer />
    </div>
  );
}